using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Preserve EF Core 8 discriminator property name so existing documents
            // (which store "Discriminator": "Product") remain readable, and direct
            // SQL queries referencing c.Discriminator continue to work.
            entity.HasDiscriminator<string>("Discriminator");

            // Preserve EF Core 8 compound id format ("Product|123") so existing
            // documents remain accessible via FindAsync / point-reads.
            entity.HasRootDiscriminatorInJsonId(true);
        });

        // HasIndex removed — Cosmos DB does not support EF-managed indexes.
        // Manage indexing policy in Azure Portal, Bicep, or Terraform.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

